@startuml
skinparam ClassBox bgcolor #f5f5f5
skinparam Actor bgcolor #e0e0e0
skinparam Interface bgcolor #f0f0f0
skinparam Relationship lineStyle dashed
skinparam RelationshipLabelBackgroundColor #ffffff

title Sistema_de_Cobranças

class Cliente {
    +id: Int
    +nome: String
    +cobranças: List<Cobrança>
    -fazerPagamento()
}

class Cobrança {
    +id: Int
    +cliente: Client
    +quitado: Boolean
    -gerarBoleto()
    -consultaBoleto(): Boolean
}

class Boleto {
    +id: Int
    +validade: Date
    +valor: Float
}

interface GerarBoleto {
}

interface PagarBoleto {
    -fazerPagamento()
}

class Cliente as actor {
    label "C"
    title "Cliente"
}

class Cobrança as actor {
    label "C"
    title "Cobrança"
}

class Boleto as actor {
    label "C"
    title "Boleto"
}

class GerarBoleto as interface {
    label "I"
    title "«interface» GerarBoleto"
}

class PagarBoleto as interface {
    label "I"
    title "«interface» PagarBoleto"
}

actor Cliente as actor1 {
    label "C"
    title "Cliente"
}

actor Cobrança as actor2 {
    label "C"
    title "Cobrança"
}

actor Boleto as actor3 {
    label "C"
    title "Boleto"
}

actor GerarBoleto as interface1 {
    label "I"
    title "«interface» GerarBoleto"
}

actor PagarBoleto as interface2 {
    label "I"
    title "«interface» PagarBoleto"
}

actor1 --|> GerarBoleto : GerarBoleto
actor2 --|> PagarBoleto : PagarBoleto
actor2 --|* Cobrança : 1
    0..*
}

actor2 --|* Boleto : 1
    1
}

@enduml
